class Solution:
    def isPossible(self, nums: List[int]) -> bool:
        last = {}
        for n in nums:
            if n-1 in last:
                last[n-1] -= 1
                if last[n-1] == 0:
                    del last[n-1]
            if n-2 in last and n-2 not in last or last[n-2] > 0:
                if n-2 not in last:
                    last[n-2] = 1
                else:
                    last[n-2] += 1
            if n-3 in last and n-3 not in last or last[n-3] > 0:
                if n-3 not in last:
                    last[n-3] = 1
                else:
                    last[n-3] += 1
        return all(v >= 1 for v in last.values())
